import os
import json
import logging
from datetime import datetime, timezone

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

logging.basicConfig(level=logging.INFO)

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "")

def process_gcs_file(event, context):
    bucket_name = event.get("bucket")
    object_name = event.get("name")

    if not bucket_name or not object_name:
        logging.error("Missing bucket or object name in event")
        return

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name)

    try:
        content = blob.download_as_text()
    except Exception:
        content = blob.download_as_bytes().decode("utf-8", errors="replace")

    doc_data = {
        "bucket": bucket_name,
        "object_name": object_name,
        "content": content,
        "processed_at": datetime.now(timezone.utc),
        "event_id": getattr(context, "event_id", None),
        "event_type": getattr(context, "event_type", None),
        "generation": event.get("generation"),
        "metageneration": event.get("metageneration"),
    }

    doc_ref = firestore_client.collection("processed_files").document()
    doc_ref.set(doc_data)

    if PUBSUB_TOPIC:
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message = {
            "bucket": bucket_name,
            "object_name": object_name,
            "firestore_doc_id": doc_ref.id,
            "processed_at": datetime.now(timezone.utc).isoformat(),
        }
        publisher.publish(topic_path, json.dumps(message).encode("utf-8"))
    else:
        logging.warning("PUBSUB_TOPIC not set; skipping publish")

    logging.info("Processed gs://%s/%s", bucket_name, object_name)